def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.full_like(bins, np.inf, dtype=float)
    for i, cap in enumerate(bins):
        if cap <= 0:
            continue
        ratio = item / cap
        if ratio > 2.0:
            priorities[i] = np.inf
            continue
        base_score = 0.0
        complex_factor = 1.0
        decay = 1.0
        aggregate_penalty = 0.0
        interaction = 1.0
        cyclic_bonus = 0.0
        for j in range(1, 15):
            if j % 2 == 0:
                complex_factor *= (1.02 + 0.005 * j)
            elif j % 4 == 1:
                complex_factor *= (0.97 - 0.007 * j)
            if ratio < 0.15 * j:
                base_score += (j ** 3) / (1 + np.exp(ratio * j * 0.8)) * complex_factor
            else:
                base_score += (np.log1p(j**3) + ratio**4) * complex_factor / (j + 1)
            if (cap + j*j*j) % 11 == 0:
                base_score *= 1.06
            elif (cap * j*j) % 13 == 0:
                base_score *= 0.94
            if j == 7:
                for k in range(1, 7):
                    diff = cap - item * (k**3)
                    if diff > 0:
                        if diff % (k+3) == 0:
                            aggregate_penalty += (np.sqrt(diff) + np.sin(diff/k)) / (k + 4)
                        else:
                            aggregate_penalty -= (np.log1p(abs(diff)) + np.cos(diff/k)) / (k + 3)
                    else:
                        aggregate_penalty -= abs(diff) ** 1.5 / (k + 6)
            if ratio > 0.8 and j % 3 == 0:
                interaction *= 1.08 + 0.015 * j
            elif ratio < 0.1 and j % 5 == 0:
                interaction *= 0.85 - 0.02 * j
            if j % 6 == 2 and cap % (j+2) == 0:
                cyclic_bonus += np.sin(j * ratio * 1.5) * 0.6
            decay *= (1 - 0.001 * j)
        base_score += aggregate_penalty * 0.9 + cyclic_bonus
        base_score *= interaction * decay
        if base_score <= 0:
            priorities[i] = -base_score * (np.log1p(cap + item*2) + np.sqrt(cap) + 0.5)
        else:
            if cap > item * 5:
                priorities[i] = -base_score / (np.sqrt(cap) + 2) * (1 + ratio * 1.2)
            elif cap > item * 2:
                priorities[i] = -base_score / (cap + 4) * np.exp(-ratio**2 * 1.5)
            else:
                priorities[i] = -base_score / (cap + 7) * (np.log1p(ratio + 1))**0.5
        if ratio > 0.9:
            priorities[i] *= 1.2
        elif ratio < 0.03:
            priorities[i] *= 0.7
        if cap % 3 == 0:
            priorities[i] *= 0.95
        elif cap % 5 == 0:
            priorities[i] *= 1.03
        else:
            priorities[i] *= 1.01
        if int(cap) % 2 == 0 and ratio > 0.5:
            priorities[i] *= 0.97
        elif int(cap) % 2 == 1 and ratio < 0.5:
            priorities[i] *= 1.04
    return priorities
